// lib/export/planExport.ts
// Branded PDF and DOCX generation for DivyaDarshan Yatra Plans

const LOGO_B64 = ""

const SAFFRON_RGB = [192, 87, 10]   as [number, number, number]
const CRIMSON_RGB = [139, 26, 26]   as [number, number, number]
const GOLD_RGB    = [212, 160, 23]  as [number, number, number]
const IVORY_RGB   = [255, 248, 240] as [number, number, number]
const WHITE_RGB   = [255, 255, 255] as [number, number, number]
const DARK_RGB    = [30,  20,  10]  as [number, number, number]
const MUTED_RGB   = [130, 110, 90]  as [number, number, number]

// ── PDF Export ─────────────────────────────────────────────────────────────
export async function downloadPDF(
  itinerary: string,
  from: string,
  to: string,
  days?: number,
  pilgrims?: number
) {
  const { jsPDF } = await import('jspdf')
  const doc    = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' })
  const pageW  = doc.internal.pageSize.getWidth()
  const pageH  = doc.internal.pageSize.getHeight()
  const margin = 16
  const usableW = pageW - margin * 2
  let y = 0
  let pageNum = 1

  const checkY = (need: number) => { if (y + need > pageH - 18) { addFooter(); doc.addPage(); pageNum++; y = 0; addContHeader() } }

  // ── Repeating footer ──────────────────────────────────────────────────
  const addFooter = () => {
    doc.setFillColor(...SAFFRON_RGB)
    doc.rect(0, pageH - 10, pageW, 10, 'F')
    doc.setFontSize(7)
    doc.setFont('helvetica', 'normal')
    doc.setTextColor(...WHITE_RGB)
    doc.text('DivyaDarshan · India\'s Temple Explorer · divyadarshan.in', margin, pageH - 3.5)
    doc.text(`Page ${pageNum}`, pageW - margin, pageH - 3.5, { align: 'right' })
  }

  // ── Continuation page header ───────────────────────────────────────────
  const addContHeader = () => {
    doc.setFillColor(...SAFFRON_RGB)
    doc.rect(0, 0, pageW, 16, 'F')
    doc.setFillColor(...GOLD_RGB)
    doc.rect(0, 15, pageW, 1.5, 'F')
    // Logo on continuation pages
    doc.addImage('data:image/png;base64,' + LOGO_B64, 'PNG', margin, 1, 48, 12)
    doc.setFontSize(8)
    doc.setFont('helvetica', 'normal')
    doc.setTextColor(...WHITE_RGB)
    doc.text(`${from} → ${to}`, pageW - margin, 9, { align: 'right' })
    y = 24
    addFooter()
  }

  // ── Cover header ─────────────────────────────────────────────────────
  // Deep saffron top band
  doc.setFillColor(...SAFFRON_RGB)
  doc.rect(0, 0, pageW, 52, 'F')

  // Gold accent line
  doc.setFillColor(...GOLD_RGB)
  doc.rect(0, 51, pageW, 2, 'F')

  // Decorative circles background
  doc.setDrawColor(255, 220, 180)
  doc.setLineWidth(0.3)
  ;[
    [pageW - 20, 15, 18],
    [pageW - 40, 35, 12],
    [15, 45, 8],
  ].forEach(([cx, cy, r]) => doc.circle(cx as number, cy as number, r as number, 'S'))

  // Logo image — white background pill
  doc.setFillColor(255, 255, 255)
  doc.roundedRect(margin, 8, 72, 22, 3, 3, 'F')
  doc.addImage('data:image/png;base64,' + LOGO_B64, 'PNG', margin + 2, 10, 68, 18)

  // YATRA PLAN badge
  doc.setFillColor(...GOLD_RGB)
  doc.roundedRect(pageW - margin - 50, 10, 50, 9, 2, 2, 'F')
  doc.setFontSize(8.5)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...CRIMSON_RGB)
  doc.text('✦  YATRA PLAN  ✦', pageW - margin - 25, 16, { align: 'center' })

  // Generated date
  doc.setFontSize(7.5)
  doc.setFont('helvetica', 'normal')
  doc.setTextColor(255, 220, 180)
  const dateStr = new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })
  doc.text(dateStr, pageW - margin, 26, { align: 'right' })
  doc.setTextColor(255, 255, 255)
  doc.text('Generated on', pageW - margin, 22, { align: 'right' })

  y = 60

  // ── Journey info card ─────────────────────────────────────────────────
  doc.setFillColor(...IVORY_RGB)
  doc.roundedRect(margin, y, usableW, 30, 3, 3, 'F')
  doc.setDrawColor(...GOLD_RGB)
  doc.setLineWidth(0.5)
  doc.roundedRect(margin, y, usableW, 30, 3, 3, 'S')
  // Left saffron accent bar
  doc.setFillColor(...SAFFRON_RGB)
  doc.roundedRect(margin, y, 3.5, 30, 1, 1, 'F')

  // Labels
  doc.setFontSize(7.5)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...MUTED_RGB)
  doc.text('FROM', margin + 9, y + 9)
  doc.text('TO', margin + 9, y + 20)

  // Values
  doc.setFontSize(13)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...CRIMSON_RGB)
  doc.text(from || '—', margin + 24, y + 10)
  doc.text(to || '—', margin + 24, y + 21)

  // Right side details
  const rightX = pageW - margin - 5
  doc.setFontSize(8)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(...SAFFRON_RGB)
  if (days) {
    doc.text(`${days} Days`, rightX, y + 9, { align: 'right' })
  }
  if (pilgrims) {
    doc.text(`${pilgrims} Pilgrim${pilgrims > 1 ? 's' : ''}`, rightX, y + 17, { align: 'right' })
  }
  doc.setFontSize(7.5)
  doc.setFont('helvetica', 'normal')
  doc.setTextColor(...MUTED_RGB)
  doc.text(dateStr, rightX, y + 25, { align: 'right' })

  y += 38
  addFooter()

  // ── Parse itinerary ───────────────────────────────────────────────────
  const lines = itinerary.split('\n').filter(l => l.trim())

  for (const raw of lines) {
    const line = raw.trim().replace(/^\*+|\*+$/g, '')
    if (!line) continue

    // Day heading
    const dayMatch = line.match(/^(day\s*(\d+))[:\-\u2013\u2014]?\s*(.*)?$/i)
    if (dayMatch) {
      checkY(18)
      // Day card header
      const dayColor = [
        CRIMSON_RGB, SAFFRON_RGB,
        [21, 128, 61] as [number,number,number],
        [29, 78, 216] as [number,number,number],
        [124, 58, 237] as [number,number,number],
      ]
      const idx = (parseInt(dayMatch[2]) - 1) % dayColor.length
      const col = dayColor[idx]

      doc.setFillColor(col[0], col[1], col[2])
      doc.roundedRect(margin, y, usableW, 13, 2, 2, 'F')

      // Day circle
      doc.setFillColor(255, 255, 255)
      doc.circle(margin + 8, y + 6.5, 5, 'F')
      doc.setFontSize(9)
      doc.setFont('helvetica', 'bold')
      doc.setTextColor(col[0], col[1], col[2])
      doc.text(dayMatch[2], margin + 8, y + 8, { align: 'center' })

      // Day title
      doc.setFontSize(11)
      doc.setFont('helvetica', 'bold')
      doc.setTextColor(...WHITE_RGB)
      const titleTxt = dayMatch[3]?.trim() || `Day ${dayMatch[2]}`
      doc.text(titleTxt.substring(0, 55), margin + 17, y + 8.5)

      y += 16
      continue
    }

    // Section headings (Tips, Budget etc.)
    if (/^(tips|important|total estimated budget|best time|key booking|dress code)/i.test(line)) {
      checkY(10)
      doc.setFillColor(255, 251, 235)
      doc.roundedRect(margin, y, usableW, 8, 1.5, 1.5, 'F')
      doc.setDrawColor(245, 158, 11)
      doc.roundedRect(margin, y, usableW, 8, 1.5, 1.5, 'S')
      doc.setFontSize(9)
      doc.setFont('helvetica', 'bold')
      doc.setTextColor(146, 64, 14)
      doc.text(`✦  ${line}`, margin + 4, y + 5.5)
      y += 11
      continue
    }

    // Bullet items
    const clean = line.replace(/^[-•*✓→▸◆\d+\.\s]+/, '').trim()
    if (!clean) continue

    const wrapped = doc.splitTextToSize(`• ${clean}`, usableW - 6)
    checkY(wrapped.length * 5 + 2)
    doc.setFontSize(9)
    doc.setFont('helvetica', 'normal')
    doc.setTextColor(...DARK_RGB)
    doc.text(wrapped, margin + 4, y)
    y += wrapped.length * 5 + 2
  }

  addFooter()
  doc.save(`DivyaDarshan-Yatra-${to.replace(/\s+/g, '-')}.pdf`)
}

// ── DOCX Export ────────────────────────────────────────────────────────────
export async function downloadDOCX(
  itinerary: string,
  from: string,
  to: string,
  pilgrims: number,
  days: number
) {
  const {
    Document, Packer, Paragraph, TextRun,
    AlignmentType, BorderStyle, ShadingType,
    ImageRun, Table, TableRow, TableCell, WidthType,
    HeightRule, convertInchesToTwip,
  } = await import('docx')

  // Convert logo base64 to Uint8Array for docx
  const logoBytes = Uint8Array.from(atob(LOGO_B64), c => c.charCodeAt(0))

  const children: any[] = []

  // ── Branded header table ───────────────────────────────────────────────
  children.push(
    new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({
          tableHeader: true,
          children: [
            // Logo cell
            new TableCell({
              shading: { type: ShadingType.SOLID, color: 'C0570A' },
              width: { size: 60, type: WidthType.PERCENTAGE },
              children: [
                new Paragraph({
                  children: [
                    new ImageRun({
                      data: logoBytes,
                      transformation: { width: 160, height: 38 },
                      type: 'png',
                    }),
                  ],
                  spacing: { before: 60, after: 60 },
                }),
              ],
            }),
            // Title cell
            new TableCell({
              shading: { type: ShadingType.SOLID, color: 'C0570A' },
              width: { size: 40, type: WidthType.PERCENTAGE },
              children: [
                new Paragraph({
                  alignment: AlignmentType.RIGHT,
                  children: [
                    new TextRun({ text: 'YATRA PLAN', bold: true, size: 28, color: 'FFD580', allCaps: true }),
                  ],
                  spacing: { before: 80, after: 20 },
                }),
                new Paragraph({
                  alignment: AlignmentType.RIGHT,
                  children: [
                    new TextRun({
                      text: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' }),
                      size: 16, color: 'FFDDB3',
                    }),
                  ],
                }),
              ],
            }),
          ],
        }),
      ],
    }),
    new Paragraph({ text: '' }),
  )

  // ── Journey info box ───────────────────────────────────────────────────
  children.push(
    new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({
          children: [
            new TableCell({
              shading: { type: ShadingType.SOLID, color: 'FFF8F0' },
              borders: {
                left:   { style: BorderStyle.SINGLE, size: 18, color: 'C0570A' },
                top:    { style: BorderStyle.SINGLE, size: 4,  color: 'D4A017' },
                bottom: { style: BorderStyle.SINGLE, size: 4,  color: 'D4A017' },
                right:  { style: BorderStyle.SINGLE, size: 4,  color: 'D4A017' },
              },
              children: [
                new Paragraph({
                  children: [
                    new TextRun({ text: 'FROM  ', bold: true, size: 18, color: '888888' }),
                    new TextRun({ text: from, bold: true, size: 24, color: '8B1A1A' }),
                    new TextRun({ text: '   →   ', bold: true, size: 22, color: 'C0570A' }),
                    new TextRun({ text: 'TO  ', bold: true, size: 18, color: '888888' }),
                    new TextRun({ text: to, bold: true, size: 24, color: '8B1A1A' }),
                  ],
                  spacing: { before: 100, after: 60 },
                }),
                new Paragraph({
                  children: [
                    new TextRun({ text: `${days} Days  ·  ${pilgrims} Pilgrim${pilgrims > 1 ? 's' : ''}  ·  Powered by DivyaDarshan`, size: 18, color: 'C0570A' }),
                  ],
                  spacing: { before: 0, after: 100 },
                }),
              ],
            }),
          ],
        }),
      ],
    }),
    new Paragraph({ text: '' }),
  )

  // ── Itinerary content ──────────────────────────────────────────────────
  const DAY_COLORS = ['8B1A1A', 'C0570A', '15803D', '1D4ED8', '7C3AED']
  let dayIdx = 0

  const lines = itinerary.split('\n').filter(l => l.trim())
  for (const raw of lines) {
    const line = raw.trim().replace(/^\*+|\*+$/g, '')
    if (!line) continue

    const dayMatch = line.match(/^(day\s*(\d+))[:\-\u2013\u2014]?\s*(.*)?$/i)
    if (dayMatch) {
      const col = DAY_COLORS[dayIdx % DAY_COLORS.length]
      dayIdx++
      children.push(
        new Paragraph({ text: '', spacing: { before: 160 } }),
        new Paragraph({
          children: [
            new TextRun({ text: `  Day ${dayMatch[2]}  `, bold: true, size: 22, color: 'FFFFFF' }),
            new TextRun({ text: `  ${dayMatch[3]?.trim() || ''}`, bold: true, size: 22, color: 'FFFFFF' }),
          ],
          shading: { type: ShadingType.SOLID, color: col },
          spacing: { before: 80, after: 80 },
        }),
      )
      continue
    }

    if (/^(tips|important|total estimated budget|best time|key booking|dress code)/i.test(line)) {
      children.push(new Paragraph({
        children: [new TextRun({ text: `✦  ${line}`, bold: true, size: 20, color: '92400E' })],
        shading: { type: ShadingType.SOLID, color: 'FFFBEB' },
        spacing: { before: 140, after: 80 },
        border: { left: { style: BorderStyle.SINGLE, size: 12, color: 'F59E0B' } },
      }))
      continue
    }

    const clean = line.replace(/^[-•*✓→▸◆\d+\.\s]+/, '').trim()
    if (!clean) continue

    // Handle **bold** inline
    const parts = clean.split(/\*\*(.*?)\*\*/g)
    const runs = parts.map((p: string, i: number) =>
      i % 2 === 1
        ? new TextRun({ text: p, bold: true, color: '8B1A1A', size: 20 })
        : new TextRun({ text: p, size: 20 })
    )
    children.push(new Paragraph({
      children: [new TextRun({ text: '• ', color: 'C0570A', size: 20 }), ...runs],
      spacing: { before: 60, after: 60 },
    }))
  }

  // ── Branded footer ─────────────────────────────────────────────────────
  children.push(
    new Paragraph({ text: '', spacing: { before: 300 } }),
    new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({
          children: [
            new TableCell({
              shading: { type: ShadingType.SOLID, color: 'C0570A' },
              children: [
                new Paragraph({
                  alignment: AlignmentType.CENTER,
                  children: [
                    new TextRun({ text: 'DivyaDarshan · India\'s Temple Explorer · divyadarshan.in', size: 16, color: 'FFFFFF', bold: true }),
                  ],
                  spacing: { before: 60, after: 60 },
                }),
              ],
            }),
          ],
        }),
      ],
    }),
  )

  const doc  = new Document({ sections: [{ children }] })
  const blob = await Packer.toBlob(doc)
  const url  = URL.createObjectURL(blob)
  const a    = document.createElement('a')
  a.href     = url
  a.download = `DivyaDarshan-Yatra-${to.replace(/\s+/g, '-')}.docx`
  a.click()
  URL.revokeObjectURL(url)
}
